solution:
function isAnagram(a, b) {
  if (a.length !== b.length) return false;
  const freq = {};
  for (let i = 0; i < a.length; i++) freq[a[i]] = (freq[a[i]] || 0) + 1;
  for (let i = 0; i < b.length; i++) {
    if (!freq[b[i]]) return false;
    freq[b[i]]--;
  }
  return true;
}

tests:
if (isAnagram("listen", "silent") !== true) throw new Error("listen");
if (isAnagram("rat", "car") !== false) throw new Error("rat");
if (isAnagram("", "") !== true) throw new Error("empty");
if (isAnagram("aabb", "bbaa") !== true) throw new Error("aabb");
if (isAnagram("a", "ab") !== false) throw new Error("len");

