function swapCase(s) {
  const parts = [];
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (c >= "a" && c <= "z") {
      parts.push(String.fromCharCode(c.charCodeAt(0) - 32));
    } else if (c >= "A" && c <= "Z") {
      parts.push(String.fromCharCode(c.charCodeAt(0) + 32));
    } else {
      parts.push(c);
    }
  }
  return parts.join("");
}

