if (startsWith("hello", "hello") !== true) throw new Error("full");
if (startsWith("hello", "world") !== false) throw new Error("world");
if (startsWith("hi", "hello") !== false) throw new Error("long");
if (startsWith("abc", "") !== true) throw new Error("empty");

