function removeVowels(s) {
  const parts = [];
  for (let i = 0; i < s.length; i++) {
    if ("aeiou".indexOf(s[i]) === -1) parts.push(s[i]);
  }
  return parts.join("");
}

tests:
if (removeVowels("banana") !== "bnn") throw new Error("banana");
if (removeVowels("xyz") !== "xyz") throw new Error("xyz");
if (removeVowels("aeiou") !== "") throw new Error("vowels");
if (removeVowels("") !== "") throw new Error("empty");
